SELECT turnout_percentage
FROM voting_patterns
WHERE election_id = 1 AND district_id = 1 AND year = 2022;

SELECT total_spent
FROM campaign_finance
WHERE candidate_id = 2 AND election_id = 1 AND year = 2022;

SELECT SUM(total_spent) AS total_spent
FROM campaign_finance
WHERE election_id = 1;

SELECT SUM(total_spent) AS total_amount_spent
FROM campaign_finance
WHERE candidate_id = 2 AND election_id = 0;
